class Solution:
    def isPrintable(self, targetGrid) -> bool:
        rows = len(targetGrid)
        cols = len(targetGrid[0])
        bounds = {}
        colors = set()
        for r in range(rows):
            for c in range(cols):
                color = targetGrid[r][c]
                colors.add(color)
                if color not in bounds:
                    bounds[color] = [r, r, c, c]
                else:
                    b = bounds[color]
                    if r < b[0]:
                        b[0] = r
                    if r > b[1]:
                        b[1] = r
                    if c < b[2]:
                        b[2] = c
                    if c > b[3]:
                        b[3] = c
        colors = sorted(colors)
        adj = {color: set() for color in colors}
        indeg = {color: 0 for color in colors}
        for a in colors:
            r0, r1, c0, c1 = bounds[a]
            covered = set()
            for r in range(r0, r1 + 1):
                for c in range(c0, c1 + 1):
                    b = targetGrid[r][c]
                    if b != a:
                        covered.add(b)
            for b in covered:
                if b not in adj[a]:
                    adj[a].add(b)
                    indeg[b] += 1
        from collections import deque
        queue = deque([color for color in colors if indeg[color] == 0])
        visited = 0
        while queue:
            u = queue.popleft()
            visited += 1
            for v in adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    queue.append(v)
        return visited == len(colors)

