var isPrintable = function(targetGrid) {
    const rows = targetGrid.length;
    const cols = targetGrid[0].length;
    const bounds = new Map();
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            const color = targetGrid[r][c];
            if (!bounds.has(color)) {
                bounds.set(color, [r, r, c, c]);
            } else {
                const b = bounds.get(color);
                if (r < b[0]) b[0] = r;
                if (r > b[1]) b[1] = r;
                if (c < b[2]) b[2] = c;
                if (c > b[3]) b[3] = c;
            }
        }
    }
    const erased = new Set();
    let remaining = new Set(bounds.keys());
    while (remaining.size > 0) {
        let progressed = false;
        for (const color of Array.from(remaining)) {
            const b = bounds.get(color);
            const r0 = b[0], r1 = b[1], c0 = b[2], c1 = b[3];
            let ok = true;
            for (let r = r0; r <= r1 && ok; r++) {
                for (let c = c0; c <= c1; c++) {
                    const cell = targetGrid[r][c];
                    if (cell !== color && !erased.has(cell)) {
                        ok = false;
                        break;
                    }
                }
            }
            if (ok) {
                erased.add(color);
                remaining.delete(color);
                progressed = true;
            }
        }
        if (!progressed) return false;
    }
    return true;
};
